import React, { useState, useEffect } from 'react';
import Sidebar from './Sidebar';
import Header from './Header';
import MLModelStatus from './MLModelStatus';
import ModelDetails from './ModelDetails';
import MLPerformanceChart from './MLPerformanceChart';
import DashboardView from './DashboardView';
import SimulationView from './SimulationView';
import DetectionView from './DetectionView';
import TransactionsView from './TransactionsView';
import SettingsView from './SettingsView';
import axios from 'axios';

const Dashboard = () => {
  const [activeSection, setActiveSection] = useState('Dashboard');
  const [transactions, setTransactions] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [backendStats, setBackendStats] = useState(null);

  const API_URL = "http://localhost:5000";

  // Fetch data from MySQL via Backend on mount and periodic refresh
  const fetchData = async () => {
    try {
      const statsRes = await axios.get(`${API_URL}/stats`);
      setBackendStats(statsRes.data);

      const txnRes = await axios.get(`${API_URL}/transactions`);
      const newTransactions = txnRes.data;

      // Update transactions state
      setTransactions(newTransactions);

      // Smart alert update: only add new fraud transactions that aren't already in alerts
      const fraudFromDB = newTransactions.filter(t => t.status !== 'approved');
      setAlerts(prevAlerts => {
        const existingIds = new Set(prevAlerts.map(a => a.id));
        const trulyNewAlerts = fraudFromDB.filter(a => !existingIds.has(a.id));
        return [...trulyNewAlerts, ...prevAlerts].slice(0, 20); // Keep last 20
      });
    } catch (err) {
      console.error("Error fetching from MySQL backend:", err);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000); // Refresh every 5s
    return () => clearInterval(interval);
  }, []);

  const handleNavigate = (section) => {
    setActiveSection(section);
  };

  const handleRunBatch = async (params) => {
    try {
      await axios.post(`${API_URL}/mlBatchCheck`, params);
      // Wait a bit for DB to commit
      setTimeout(() => {
        fetchData();
        setActiveSection('Transactions');
      }, 500);
    } catch (err) {
      console.error("Batch Simulation Error:", err);
    }
  };

  const handleRunSingle = async (data) => {
    try {
      // Connect to REAL ML Backend API which saves to MySQL
      const payload = {
        amount: parseFloat(data.amount),
        is_night: data.isNight ? 1 : 0,
        location: data.location,
        merchant: data.merchant,
        location_risk: Math.random() > 0.8 ? 1 : 0, 
        merchant_risk: Math.random() > 0.8 ? 1 : 0,
        velocity_flag: Math.random() > 0.9 ? 1 : 0
      };

      await axios.post(`${API_URL}/mlFraudCheck`, payload);

      // Wait a bit for DB to commit
      setTimeout(() => {
        fetchData();
        setActiveSection('Transactions');
      }, 500);
    } catch (err) {
      console.error("ML API Error:", err);
    }
  };

  const handleClearAlerts = () => {
    setAlerts([]);
  };

  const renderContent = () => {
    switch (activeSection) {
      case 'Dashboard':
        return <DashboardView transactions={transactions} alerts={alerts} onClearAlerts={handleClearAlerts} />;
      case 'Simulation':
        return <SimulationView onRunBatch={handleRunBatch} onRunSingle={handleRunSingle} />;
      case 'Detection':
        return <DetectionView />;
      case 'Analytics':
        return (
          <div style={{ padding: '2rem' }}>
            <MLModelStatus stats={backendStats} />
            <ModelDetails stats={backendStats} />
            <MLPerformanceChart />
          </div>
        );
      case 'Transactions':
        return <TransactionsView transactions={transactions} />;
      case 'Settings':
        return <SettingsView />;
      default:
        return <DashboardView transactions={transactions} alerts={alerts} onClearAlerts={handleClearAlerts} />;
    }
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', backgroundColor: '#0f172a', color: 'white', fontFamily: 'Inter, sans-serif' }}>
      <Sidebar activeSection={activeSection} onNavigate={handleNavigate} />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
        <Header activeSection={activeSection} />
        {renderContent()}
      </main>
    </div>
  );
};

export default Dashboard;
